def main(docs: list) -> dict:
    if not docs:
        return {"formatted_context": "ไม่พบข้อมูลจากแหล่งอ้างอิง"}
    parts = []
    seen = []
    for doc in docs:
        if not isinstance(doc, dict):
            continue
        meta = doc.get("metadata", {})
        name = meta.get("document_name", "Unknown")
        content = doc.get("content", "").strip()
        entry = "[" + name + "]" + chr(10) + content
        parts.append(entry)
        if name not in seen:
            seen.append(name)
    book_list = ", ".join(seen)
    sep = chr(10) + chr(10) + "---" + chr(10) + chr(10)
    body = sep.join(parts)
    ref = chr(10) + chr(10) + "(จาก: " + book_list + ")"
    return {"formatted_context": body + ref}
